styles:
.features-page .hero {
      background: white;
      position: relative;
      overflow: hidden;
    }
    .features-page .header {
      border-bottom: 1px solid var(--border);
    }
    .feature-card {
      transition: all 0.3s ease;
      border: 1px solid var(--border);
    }
    .feature-card:hover {
      transform: translateY(-4px);
      box-shadow: 0 12px 40px rgba(79, 70, 229, 0.15);
      border-color: var(--primary);
    }
    .feature-icon {
      width: 56px;
      height: 56px;
      display: flex;
      align-items: center;
      justify-content: center;
      background: linear-gradient(135deg, rgba(79, 70, 229, 0.1) 0%, rgba(139, 92, 246, 0.1) 100%);
      border-radius: 12px;
      margin-bottom: 1rem;
      transition: all 0.3s ease;
    }
    .feature-card:hover .feature-icon {
      background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
    }
    .feature-card:hover .feature-icon svg {
      stroke: white;
    }
    .feature-grid-2 {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 1.5rem;
    }
    .feature-grid-3 {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 2rem;
    }
    .feature-visual {
      position: relative;
      border-radius: 16px;
      overflow: hidden;
      box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
    }
    .feature-visual::before {
      content: '';
      position: absolute;
      top: -2px;
      left: -2px;
      right: -2px;
      bottom: -2px;
      background: linear-gradient(135deg, var(--primary), var(--accent), var(--primary));
      border-radius: 18px;
      z-index: -1;
      opacity: 0.3;
    }
    .feature-section {
      position: relative;
    }
    .feature-section::before {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      height: 1px;
      background: linear-gradient(90deg, transparent, var(--border), transparent);
    }
    .stat-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      padding: 2rem;
      text-align: center;
      transition: all 0.3s ease;
    }
    .stat-card:hover {
      border-color: var(--primary);
      transform: translateY(-2px);
    }
    .stat-number {
      font-size: 3rem;
      font-weight: 700;
      background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      line-height: 1;
      margin-bottom: 0.5rem;
    }
    .comparison-table {
      width: 100%;
      border-collapse: collapse;
      margin: 2rem 0;
    }
    .comparison-table th,
    .comparison-table td {
      padding: 1rem;
      text-align: left;
      border-bottom: 1px solid var(--border);
    }
    .comparison-table th {
      background: var(--bg-secondary);
      font-weight: 600;
    }
    .comparison-table tr:hover td {
      background: rgba(79, 70, 229, 0.05);
    }
    .check-icon {
      color: var(--success);
    }
    .nav-tabs {
      display: flex;
      gap: 1rem;
      margin-bottom: 2rem;
      border-bottom: 1px solid var(--border);
      padding-bottom: 1rem;
      overflow-x: auto;
    }
    .nav-tab {
      padding: 0.75rem 1.5rem;
      border-radius: 8px;
      white-space: nowrap;
      transition: all 0.3s ease;
      background: transparent;
      border: 1px solid transparent;
    }
    .nav-tab:hover {
      background: var(--bg-secondary);
    }
    .nav-tab.active {
      background: var(--primary);
      color: white;
    }
    .tab-content {
      display: none;
    }
    .tab-content.active {
      display: block;
    }
    @media (max-width: 1024px) {
      .feature-grid-3 {
        grid-template-columns: repeat(2, 1fr);
      }
      .feature-grid-2 {
        grid-template-columns: 1fr;
      }
      .security-grid {
        grid-template-columns: repeat(2, 1fr) !important;
      }
      #messaging > .container > div[style*="grid-template-columns: 1fr 1fr"] {
        grid-template-columns: 1fr !important;
        gap: 2rem !important;
      }
      .grid[style*="repeat(4, 1fr)"] {
        grid-template-columns: repeat(2, 1fr) !important;
      }
      [style*="grid-template-columns: repeat(3, 1fr)"] {
        grid-template-columns: repeat(2, 1fr) !important;
      }
    }
    @media (max-width: 768px) {
      .feature-grid-3 {
        grid-template-columns: 1fr;
      }
      .security-grid {
        grid-template-columns: 1fr !important;
      }
      .hero {
        padding: 6rem 0 3rem !important;
      }
      .hero h1 {
        font-size: 1.75rem;
      }
      .hero-subtitle {
        font-size: 1rem !important;
      }
      .comparison-table {
        font-size: 0.875rem;
      }
      .comparison-table th,
      .comparison-table td {
        padding: 0.75rem 0.5rem;
      }
      .stat-number {
        font-size: 2.5rem;
      }
      [style*="grid-template-columns: 1fr 1fr"] {
        grid-template-columns: 1fr !important;
        gap: 2rem !important;
      }
      [style*="grid-template-columns: repeat(2, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      [style*="grid-template-columns: repeat(3, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      [style*="grid-template-columns: repeat(4, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      .section-header h2 {
        font-size: 1.5rem;
      }
      .section-header p {
        font-size: 0.9375rem;
      }
      .feature-card {
        padding: 1.5rem !important;
      }
      .cta-section {
        padding: 2rem 1.5rem !important;
      }
      .cta-section h2 {
        font-size: 1.5rem !important;
      }
    }
    @media (max-width: 576px) {
      .nav-tabs {
        gap: 0.5rem;
      }
      .nav-tab {
        padding: 0.5rem 1rem;
        font-size: 0.875rem;
      }
      .hero-content {
        padding: 0 1rem;
      }
      .feature-grid-2 > div {
        grid-template-columns: 1fr !important;
      }
      [style*="grid-template-columns: repeat(4, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      .security-grid .stat-card {
        text-align: center;
      }
      .security-grid .feature-icon {
        margin-left: auto;
        margin-right: auto;
      }
      .section {
        padding: 3rem 0 !important;
      }
      .section-header {
        margin-bottom: 2rem !important;
      }
      .btn-lg {
        padding: 0.75rem 1.5rem;
        font-size: 0.9375rem;
      }
    }
    @media (max-width: 480px) {
      [style*="grid-template-columns: repeat(2, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      [style*="grid-template-columns: repeat(3, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
      .hero-actions {
        flex-direction: column;
        width: 100%;
      }
      .hero-actions .btn {
        width: 100%;
        justify-content: center;
      }
      #messaging .section-header + div > div:first-child {
        order: 2;
      }
      #messaging .section-header + div > div:last-child {
        order: 1;
      }
    }

    @media (max-width: 375px) {
      .section-header h2 {
        font-size: 1.25rem;
      }
      .feature-card h3 {
        font-size: 1rem !important;
      }
      .feature-card p {
        font-size: 0.875rem !important;
      }
    }

    @media (max-width: 768px) {
      section.section {
        padding: 3rem 0 !important;
      }
      #messaging {
        padding: 3rem 0 !important;
      }
      #messaging [style*="grid-template-columns: repeat(2, 1fr)"] {
        grid-template-columns: 1fr !important;
      }
    }
